// Clear previous run data AND normalize column names
// This handles any column name format from your sheet
const staticData = $getWorkflowStaticData('global');
staticData.allResults = [];

const items = $input.all();
const normalized = [];

for (const item of items) {
  const raw = item.json;
  const keys = Object.keys(raw);

  // Find product name column (flexible matching)
  const nameKey = keys.find(k => 
    k.toLowerCase().replace(/[^a-z]/g, '') === 'productname' ||
    k.toLowerCase() === 'product_name' ||
    k.toLowerCase() === 'product name' ||
    k.toLowerCase() === 'name' ||
    k.toLowerCase() === 'title' ||
    k.toLowerCase() === 'item' ||
    k.toLowerCase() === 'product'
  );

  // Find SKU column
  const skuKey = keys.find(k => 
    k.toLowerCase() === 'sku' ||
    k.toLowerCase() === 'id' ||
    k.toLowerCase() === 'product_id'
  );

  // Find price column
  const priceKey = keys.find(k => 
    k.toLowerCase().replace(/[^a-z]/g, '') === 'myprice' ||
    k.toLowerCase() === 'my_price' ||
    k.toLowerCase() === 'price' ||
    k.toLowerCase() === 'selling_price' ||
    k.toLowerCase() === 'our price' ||
    k.toLowerCase() === 'my price'
  );

  // Find cost column
  const costKey = keys.find(k => 
    k.toLowerCase().replace(/[^a-z]/g, '') === 'mycost' ||
    k.toLowerCase() === 'my_cost' ||
    k.toLowerCase() === 'cost' ||
    k.toLowerCase() === 'our cost' ||
    k.toLowerCase() === 'my cost'
  );

  const productName = nameKey ? raw[nameKey] : null;
  const price = priceKey ? raw[priceKey] : null;

  if (!productName || !price) continue; // Skip empty rows

  normalized.push({
    json: {
      product_name: String(productName).trim(),
      sku: skuKey ? String(raw[skuKey]).trim() : '',
      my_price: String(price).replace(/[^0-9.]/g, ''),
      my_cost: costKey ? String(raw[costKey]).replace(/[^0-9.]/g, '') : '0'
    }
  });
}

if (normalized.length === 0) {
  return [{ json: { error: 'No products found. Check your sheet column names. Found columns: ' + Object.keys(items[0]?.json || {}).join(', ') } }];
}

return normalized;

// Pass through product data for search
const item = $input.first().json;
return $input.all();

const product = $('Loop Through Each Product').first().json;
const response = $input.first().json;

const results = response.shopping_results || response.inline_shopping_results || [];
const prices = [];

for (const item of results) {
  let price = item.price || item.extracted_price || 0;
  if (typeof price === 'string') {
    price = parseFloat(price.replace(/[^0-9.]/g, ''));
  }
  if (price > 0) {
    prices.push({
      seller: item.source || item.merchant || 'Unknown',
      price: price,
      title: item.title || ''
    });
  }
}

if (prices.length === 0) {
  return [{
    json: {
      product_name: product.product_name,
      sku: product.sku || '',
      my_price: parseFloat(product.my_price),
      my_cost: parseFloat(product.my_cost || 0),
      margin_now: null,
      competitor_lowest: null,
      competitor_average: null,
      competitor_highest: null,
      competitor_count: 0,
      gap_pct: null,
      signal: 'NO_DATA',
      severity: 'info',
      suggested_price: null,
      margin_suggested: null,
      action: 'No competitor prices found',
      date: new Date().toISOString().split('T')[0]
    }
  }];
}

const priceValues = prices.map(p => p.price).sort((a, b) => a - b);
const lowest = Math.min(...priceValues);
const highest = Math.max(...priceValues);
const average = parseFloat((priceValues.reduce((a, b) => a + b, 0) / priceValues.length).toFixed(2));

const myPrice = parseFloat(product.my_price);
const myCost = parseFloat(product.my_cost || 0);
const gapPct = parseFloat(((myPrice - average) / average * 100).toFixed(1));

let signal, severity, action, suggestedPrice;

if (myPrice < average * 0.85) {
  signal = 'UNDERPRICED';
  severity = 'critical';
  suggestedPrice = parseFloat((average * 0.95).toFixed(2));
  if (myCost > 0 && suggestedPrice < myCost * 1.15) suggestedPrice = parseFloat((myCost * 1.15).toFixed(2));
  action = 'RAISE to $' + suggestedPrice + ' — you are ' + Math.abs(gapPct) + '% below market';
} else if (myPrice < average * 0.95) {
  signal = 'SLIGHTLY_UNDER';
  severity = 'warning';
  suggestedPrice = parseFloat((average * 0.97).toFixed(2));
  action = 'Consider raising to $' + suggestedPrice;
} else if (myPrice > average * 1.15) {
  signal = 'OVERPRICED';
  severity = 'critical';
  suggestedPrice = parseFloat((average * 1.05).toFixed(2));
  if (myCost > 0 && suggestedPrice < myCost * 1.15) suggestedPrice = parseFloat((myCost * 1.15).toFixed(2));
  action = 'LOWER to $' + suggestedPrice + ' — you are ' + gapPct + '% above market';
} else if (myPrice > average * 1.05) {
  signal = 'SLIGHTLY_OVER';
  severity = 'warning';
  suggestedPrice = parseFloat((average * 1.03).toFixed(2));
  action = 'Consider lowering to $' + suggestedPrice;
} else {
  signal = 'COMPETITIVE';
  severity = 'ok';
  suggestedPrice = myPrice;
  action = 'Price is competitive — no change needed';
}

const marginNow = myCost > 0 ? parseFloat(((myPrice - myCost) / myPrice * 100).toFixed(1)) : null;
const marginSuggested = myCost > 0 ? parseFloat(((suggestedPrice - myCost) / suggestedPrice * 100).toFixed(1)) : null;

return [{
  json: {
    product_name: product.product_name,
    sku: product.sku || '',
    my_price: myPrice,
    my_cost: myCost,
    margin_now: marginNow,
    competitor_lowest: lowest,
    competitor_average: average,
    competitor_highest: highest,
    competitor_count: prices.length,
    gap_pct: gapPct,
    signal: signal,
    severity: severity,
    suggested_price: suggestedPrice,
    margin_suggested: marginSuggested,
    action: action,
    date: new Date().toISOString().split('T')[0]
  }
}];

// Save analyzed result to memory for daily summary
const staticData = $getWorkflowStaticData('global');
if (!staticData.allResults) staticData.allResults = [];
staticData.allResults.push($input.first().json);
return $input.all();

