// Build daily summary from ALL collected results in memory
const staticData = $getWorkflowStaticData('global');
const allResults = staticData.allResults || [];

// Clear for next run
staticData.allResults = [];

if (allResults.length === 0) {
  return [{
    json: {
      summary: 'DAILY PRICING REPORT — ' + new Date().toISOString().split('T')[0] + '\n\nNo products were analyzed today.',
      summary_html: '<h2>Daily Pricing Report</h2><p>No products analyzed today.</p>',
      has_alerts: false,
      date: new Date().toISOString().split('T')[0],
      total_products: 0,
      critical_count: 0,
      warning_count: 0
    }
  }];
}

const critical = allResults.filter(r => r.severity === 'critical');
const warnings = allResults.filter(r => r.severity === 'warning');
const ok = allResults.filter(r => r.severity === 'ok');
const noData = allResults.filter(r => r.signal === 'NO_DATA');
const underpriced = allResults.filter(r => r.signal === 'UNDERPRICED' || r.signal === 'SLIGHTLY_UNDER');
const overpriced = allResults.filter(r => r.signal === 'OVERPRICED' || r.signal === 'SLIGHTLY_OVER');

const today = new Date().toISOString().split('T')[0];

let summary = 'DAILY PRICING REPORT — ' + today + '\n';
summary += 'Products checked: ' + allResults.length + '\n\n';
summary += 'Critical: ' + critical.length + '\n';
summary += 'Warnings: ' + warnings.length + '\n';
summary += 'Competitive: ' + ok.length + '\n';
summary += 'No data: ' + noData.length + '\n\n';

if (underpriced.length > 0) {
  summary += 'Underpriced (raise for margin):\n';
  for (const p of underpriced) {
    summary += '• ' + p.product_name + ': $' + p.my_price + ' → $' + p.suggested_price + ' (' + Math.abs(p.gap_pct) + '% below avg)\n';
  }
  summary += '\n';
}

if (overpriced.length > 0) {
  summary += 'Overpriced (lower to compete):\n';
  for (const p of overpriced) {
    summary += '• ' + p.product_name + ': $' + p.my_price + ' → $' + p.suggested_price + ' (' + p.gap_pct + '% above avg)\n';
  }
}

let html = '<h2>Daily Pricing Report — ' + today + '</h2>';
html += '<p>Products checked: <strong>' + allResults.length + '</strong></p>';
html += '<table style="border-collapse:collapse;width:100%;">';
html += '<tr style="background:#f0f0f0;"><th style="padding:8px;border:1px solid #ddd;">Status</th><th style="padding:8px;border:1px solid #ddd;">Count</th></tr>';
html += '<tr><td style="padding:8px;border:1px solid #ddd;">Critical</td><td style="padding:8px;border:1px solid #ddd;">' + critical.length + '</td></tr>';
html += '<tr><td style="padding:8px;border:1px solid #ddd;">Warnings</td><td style="padding:8px;border:1px solid #ddd;">' + warnings.length + '</td></tr>';
html += '<tr><td style="padding:8px;border:1px solid #ddd;">Competitive</td><td style="padding:8px;border:1px solid #ddd;">' + ok.length + '</td></tr>';
html += '<tr><td style="padding:8px;border:1px solid #ddd;">No Data</td><td style="padding:8px;border:1px solid #ddd;">' + noData.length + '</td></tr>';
html += '</table>';

if (underpriced.length > 0) {
  html += '<h3>Underpriced</h3><table style="border-collapse:collapse;width:100%;">';
  html += '<tr style="background:#d4edda;"><th style="padding:6px;border:1px solid #ddd;">Product</th><th style="padding:6px;border:1px solid #ddd;">Your Price</th><th style="padding:6px;border:1px solid #ddd;">Suggested</th><th style="padding:6px;border:1px solid #ddd;">Gap</th></tr>';
  for (const p of underpriced) {
    html += '<tr><td style="padding:6px;border:1px solid #ddd;">' + p.product_name + '</td><td style="padding:6px;border:1px solid #ddd;">$' + p.my_price + '</td><td style="padding:6px;border:1px solid #ddd;"><strong>$' + p.suggested_price + '</strong></td><td style="padding:6px;border:1px solid #ddd;">' + Math.abs(p.gap_pct) + '% below</td></tr>';
  }
  html += '</table>';
}

if (overpriced.length > 0) {
  html += '<h3>Overpriced</h3><table style="border-collapse:collapse;width:100%;">';
  html += '<tr style="background:#f8d7da;"><th style="padding:6px;border:1px solid #ddd;">Product</th><th style="padding:6px;border:1px solid #ddd;">Your Price</th><th style="padding:6px;border:1px solid #ddd;">Suggested</th><th style="padding:6px;border:1px solid #ddd;">Gap</th></tr>';
  for (const p of overpriced) {
    html += '<tr><td style="padding:6px;border:1px solid #ddd;">' + p.product_name + '</td><td style="padding:6px;border:1px solid #ddd;">$' + p.my_price + '</td><td style="padding:6px;border:1px solid #ddd;"><strong>$' + p.suggested_price + '</strong></td><td style="padding:6px;border:1px solid #ddd;">' + p.gap_pct + '% above</td></tr>';
  }
  html += '</table>';
}

return [{
  json: {
    summary: summary,
    summary_html: html,
    has_alerts: critical.length + warnings.length > 0,
    date: today,
    total_products: allResults.length,
    critical_count: critical.length,
    warning_count: warnings.length
  }
}];
